import React, { useState } from 'react';
import axios from 'axios';
import { Upload, Loader2 } from 'lucide-react';

const CLOUD_NAME = "dwpgncjgn";
const UPLOAD_PRESET = "productos"; 
const API_URL = "http://localhost:5000";

const SubirImagenes = ({ onFinished }) => {
    const [loading, setLoading] = useState(false);

    // Función para que el nombre sea compatible con Cloudinary y fácil de buscar
    const limpiarNombre = (nombre) => {
        return nombre
            .toLowerCase()
            .normalize("NFD")
            .replace(/[\u0300-\u036f]/g, "") // Quita acentos
            .replace(/[^a-z0-9]/g, '-')      // Cambia todo lo raro por guiones
            .replace(/-+/g, '-')             // Quita guiones dobles
            .replace(/^-|-$/g, '');          // Quita guiones al inicio o final
    };

    const handleUpload = async (e) => {
        const files = Array.from(e.target.files);
        if (files.length === 0) return;
        
        setLoading(true);
        try {
            for (const file of files) {
                const nombreLimpio = limpiarNombre(file.name.split('.')[0]);
                
                const formData = new FormData();
                formData.append('file', file);
                formData.append('upload_preset', UPLOAD_PRESET);
                // Le pedimos a Cloudinary que use nuestro nombre limpio
                formData.append('public_id', nombreLimpio); 

                const res = await axios.post(
                    `https://api.cloudinary.com/v1_1/${CLOUD_NAME}/image/upload`,
                    formData
                );

                // Guardamos el PUBLIC_ID exacto que nos devuelve Cloudinary
                await axios.post(`${API_URL}/api/galeria`, {
                    nombreReferencia: nombreLimpio, 
                    publicId: res.data.public_id,
                    url: res.data.secure_url,
                    formato: res.data.format
                });
            }
            alert("¡Imágenes subidas y normalizadas!");
            if (onFinished) onFinished();
        } catch (err) {
            console.error("Error al cargar:", err.response?.data || err.message);
            alert("Error al cargar. Posiblemente el nombre ya existe o es inválido.");
        } finally {
            setLoading(false);
            e.target.value = null;
        }
    };

    return (
        <div>
            <input type="file" id="file-input" multiple onChange={handleUpload} style={{ display: 'none' }} accept="image/*" />
            <label htmlFor="file-input" style={btnStyle}>
                {loading ? <Loader2 className="animate-spin" size={18} /> : <Upload size={18} />}
                {loading ? "Normalizando..." : "Cargar Imágenes"}
            </label>
        </div>
    );
};

const btnStyle = { background: '#1e293b', color: 'white', padding: '10px 20px', borderRadius: '12px', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer' };

export default SubirImagenes;
